function getSimulation(attack) {
  if (!attack) return ATTACK_SIMULATIONS.default;
  return ATTACK_SIMULATIONS[attack.toLowerCase().replace(/ /g,"_")] || ATTACK_SIMULATIONS.default;
}

function AttackSimPanel({ finding, onClose }) {
  const sim = getSimulation(finding.attack);
  const [activeStep, setActiveStep] = useState(0);
  const [running, setRunning] = useState(false);

  const runSimulation = async () => {
    setRunning(true);
    setActiveStep(0);
    for (let i = 0; i < sim.steps.length; i++) {
      await new Promise(r => setTimeout(r, 1200));
      setActiveStep(i + 1);
    }
    setRunning(false);
  };

  return (
    <div style={{ position: "fixed", top: 0, left: 0, right: 0, bottom: 0, backgroundColor: "rgba(0,0,0,0.85)", zIndex: 1000, display: "flex", alignItems: "center", justifyContent: "center", padding: "20px" }}
      onClick={onClose}>
      <div style={{ backgroundColor: "#030712", borderRadius: "24px", border: "1px solid rgba(255,68,68,0.4)", padding: "36px", maxWidth: "720px", width: "100%", maxHeight: "90vh", overflowY: "auto", boxShadow: "0 0 80px rgba(255,68,68,0.25), 0 0 160px rgba(255,68,68,0.1)" }}
        onClick={e => e.stopPropagation()}>

        {/* Header */}
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: "24px" }}>
          <div>
            <div style={{ display: "flex", alignItems: "center", gap: "10px", marginBottom: "8px" }}>
              <span style={{ fontSize: "20px" }}>⚡</span>
              <h3 style={{ color: "#ff4444", fontSize: "20px", fontWeight: "800", margin: 0 }}>Attack Simulation</h3>
              <span style={{ padding: "3px 10px", borderRadius: "6px", backgroundColor: "rgba(255,68,68,0.15)", color: "#ff4444", fontSize: "11px", fontWeight: "700", border: "1px solid rgba(255,68,68,0.3)" }}>EDUCATIONAL ONLY</span>
            </div>
            <div style={{ color: COLORS.text, fontSize: "16px", fontWeight: "700" }}>{sim.title}</div>
            <div style={{ display: "flex", gap: "16px", marginTop: "8px" }}>
              <span style={{ color: COLORS.muted, fontSize: "12px" }}>⏱ {sim.time}</span>
              <span style={{ color: COLORS.muted, fontSize: "12px" }}>🎯 Skill: {sim.skill}</span>
              <span style={{ color: "#ff4444", fontSize: "12px", fontWeight: "600" }}>Risk: {sim.risk}</span>
            </div>
          </div>
          <button onClick={onClose} style={{ background: "none", border: "none", color: COLORS.muted, cursor: "pointer", fontSize: "20px" }}>✕</button>
        </div>

        {/* Warning */}
        <div style={{ padding: "12px 16px", borderRadius: "10px", backgroundColor: "rgba(245,158,11,0.1)", border: "1px solid rgba(245,158,11,0.3)", marginBottom: "24px", fontSize: "13px", color: "#f59e0b" }}>
          ⚠ This simulation shows how attackers exploit this vulnerability. All commands shown are for educational purposes only. Never run these against systems you don't own.
        </div>

        {/* Run button */}
        {!running && activeStep === 0 && (
          <button onClick={runSimulation}
            style={{ width: "100%", padding: "16px", borderRadius: "12px", background: "linear-gradient(135deg, rgba(255,68,68,0.2), rgba(255,68,68,0.05))", border: "1px solid rgba(255,68,68,0.5)", color: "#ff4444", fontSize: "16px", fontWeight: "800", cursor: "pointer", marginBottom: "24px", boxShadow: "0 0 30px rgba(255,68,68,0.2)", letterSpacing: "0.02em" }}>
            ▶ Run Attack Simulation
          </button>
        )}

        {/* Attack steps */}
        <div style={{ marginBottom: "24px" }}>
          {sim.steps.map((step, i) => (
            <div key={i} style={{ marginBottom: "12px", opacity: activeStep > i ? 1 : activeStep === i && running ? 0.7 : 0.3, transition: "opacity 0.5s" }}>
              <div style={{ display: "flex", alignItems: "center", gap: "10px", marginBottom: "8px" }}>
                <span style={{ fontSize: "18px" }}>{activeStep > i ? "✅" : step.icon}</span>
                <span style={{ color: step.color, fontSize: "13px", fontWeight: "700" }}>{step.phase}</span>
                {activeStep === i + 1 && running && <span style={{ color: "#f59e0b", fontSize: "11px" }}>● Running...</span>}
              </div>
              <div style={{ padding: "14px 18px", borderRadius: "10px", backgroundColor: "#000510", border: `1px solid ${step.color}40`, fontFamily: "JetBrains Mono, monospace", fontSize: "13px", color: step.color, marginBottom: "8px", boxShadow: activeStep > i ? `0 0 20px ${step.color}15` : "none", transition: "box-shadow 0.5s" }}>
                <span style={{ color: "#475569", marginRight: "8px" }}>$</span>{step.cmd}
              </div>
              <div style={{ color: COLORS.muted, fontSize: "13px", paddingLeft: "28px" }}>{step.desc}</div>
            </div>
          ))}
        </div>

        {/* Impact */}
        {activeStep >= sim.steps.length && (
          <div style={{ padding: "24px", borderRadius: "16px", backgroundColor: "rgba(255,68,68,0.08)", border: "1px solid rgba(255,68,68,0.35)", marginBottom: "20px", boxShadow: "0 0 40px rgba(255,68,68,0.1)" }}>
            <div style={{ color: "#ff4444", fontWeight: "800", fontSize: "16px", marginBottom: "16px", display: "flex", alignItems: "center", gap: "8px" }}>💀 Attack Complete — Potential Impact:</div>
            {sim.impact.map((imp, i) => (
              <div key={i} style={{ display: "flex", alignItems: "center", gap: "8px", color: COLORS.muted, fontSize: "13px", marginBottom: "6px" }}>
                <div style={{ width: "6px", height: "6px", borderRadius: "50%", backgroundColor: "#ff4444", flexShrink: 0 }} />
                {imp}
              </div>
            ))}
          </div>
        )}

        {/* Fix reminder */}
        <div style={{ padding: "16px", borderRadius: "12px", backgroundColor: "rgba(0,255,136,0.08)", border: "1px solid rgba(0,255,136,0.25)", display: "flex", alignItems: "center", gap: "12px" }}>
          <span style={{ fontSize: "20px" }}>🛡️</span>
          <div>
            <div style={{ color: "#00ff88", fontWeight: "700", fontSize: "13px", marginBottom: "4px" }}>How to prevent this attack</div>
            <div style={{ color: COLORS.muted, fontSize: "13px" }}>Use the View Fix button to see step-by-step remediation commands.</div>
          </div>
        </div>
      </div>
    </div>
  );
}

function FindingRow({ finding, token, onStatusUpdate }) {
  const [open, setOpen]           = useState(false);
  const [showFix, setShowFix]     = useState(false);
  const [showSim, setShowSim]     = useState(false);
  const [fixStatus, setFixStatus] = useState(finding.fix_status || "open");
  const cfg = SEVERITY_CONFIG[finding.severity] || SEVERITY_CONFIG.INFO;

  const STATUS_COLORS = {
    open:          COLORS.critical,
    in_progress:   COLORS.high,
    fixed:         COLORS.low,
    accepted_risk: COLORS.muted,
  };

  const handleStatusUpdate = (findingId, newStatus) => {
    setFixStatus(newStatus);
    if (onStatusUpdate) onStatusUpdate(findingId, newStatus);
  };

  return (
    <>
      {showSim && (
        <AttackSimPanel
          finding={finding}
          onClose={() => setShowSim(false)}
        />
      )}
      {showFix && (
        <FixPanel
          finding={{ ...finding, fix_status: fixStatus }}
          token={token}
          onClose={() => setShowFix(false)}
          onStatusUpdate={handleStatusUpdate}
        />
      )}
      <div className="rounded-xl border overflow-hidden transition-all duration-200"
        style={{ backgroundColor: COLORS.card, borderColor: open ? cfg.color + "40" : COLORS.border }}>
        <div className="flex items-center justify-between p-4"
          style={{ cursor: "pointer" }}
          onClick={() => setOpen(!open)}>
          <div className="flex items-center gap-3">
            <div className="w-1 h-10 rounded-full flex-shrink-0" style={{ backgroundColor: cfg.color }} />
            <div>
              <div className="font-semibold text-sm" style={{ color: COLORS.text }}>{finding.attack}</div>
              <div className="text-xs mt-0.5" style={{ color: COLORS.muted }}>
                {finding.module} — {finding.target}
              </div>
            </div>
          </div>
          <div className="flex items-center gap-2">
            {/* Fix status badge */}
            <div className="px-2 py-1 rounded-lg text-xs font-bold"
              style={{
                backgroundColor: (STATUS_COLORS[fixStatus] || COLORS.muted) + "20",
                color: STATUS_COLORS[fixStatus] || COLORS.muted,
                border: `1px solid ${(STATUS_COLORS[fixStatus] || COLORS.muted) + "40"}`
              }}>
              {fixStatus.replace("_", " ")}
            </div>
            <SeverityBadge severity={finding.severity} />
            {/* View Fix button */}
            <button
              onClick={e => { e.stopPropagation(); setShowFix(true); }}
              className="px-3 py-1.5 rounded-lg text-xs font-bold transition-all"
              style={{
                backgroundColor: COLORS.blue + "20",
                color: COLORS.blue,
                border: `1px solid ${COLORS.blue + "40"}`
              }}>
              View Fix
            </button>
            <button
              onClick={e => { e.stopPropagation(); setShowSim(true); }}
              className="px-3 py-1.5 rounded-lg text-xs font-bold transition-all"
              style={{ backgroundColor: "#ff444420", color: "#ff4444", border: "1px solid #ff444440" }}>
              ⚡ Simulate Attack
            </button>
            {open
              ? <ChevronUp size={16} style={{ color: COLORS.muted }} />
              : <ChevronDown size={16} style={{ color: COLORS.muted }} />}
          </div>
        </div>
        {open && (
          <div className="px-4 pb-4 pt-2 border-t" style={{ borderColor: COLORS.border }}>
            <p className="text-sm leading-relaxed mb-3" style={{ color: COLORS.muted }}>{finding.description}</p>
            {/* MITRE ATT&CK Badge */}
            {(() => {
              const mitre = getMitreInfo(finding.attack);
              return (
                <div style={{ display: "flex", alignItems: "flex-start", gap: "10px", padding: "12px 14px", borderRadius: "10px", backgroundColor: "rgba(255,68,68,0.06)", border: "1px solid rgba(255,68,68,0.2)", marginTop: "8px" }}>
                  <div style={{ flexShrink: 0, padding: "4px 8px", borderRadius: "6px", backgroundColor: "rgba(255,68,68,0.15)", border: "1px solid rgba(255,68,68,0.3)" }}>
                    <div style={{ fontSize: "10px", fontWeight: "800", color: "#ff4444", fontFamily: "monospace", letterSpacing: "0.05em" }}>MITRE</div>
                    <div style={{ fontSize: "11px", fontWeight: "700", color: "#ff6666", fontFamily: "monospace" }}>{mitre.id}</div>
                  </div>
                  <div style={{ flex: 1 }}>
                    <div style={{ display: "flex", alignItems: "center", gap: "8px", flexWrap: "wrap" }}>
                      <span style={{ fontSize: "13px", fontWeight: "700", color: COLORS.text }}>{mitre.name}</span>
                      <span style={{ fontSize: "11px", padding: "2px 8px", borderRadius: "100px", backgroundColor: "rgba(245,158,11,0.15)", color: "#f59e0b", border: "1px solid rgba(245,158,11,0.3)", fontWeight: "600" }}>{mitre.tactic}</span>
                    </div>
                    <div style={{ fontSize: "12px", color: COLORS.muted, marginTop: "4px" }}>
                      🔴 Known threat groups: <span style={{ color: "#ff8888", fontWeight: "600" }}>{mitre.groups}</span>
                    </div>
                  </div>
                  <a href={`https://attack.mitre.org/techniques/${mitre.id.replace(".", "/")}`} target="_blank" rel="noreferrer"
                    style={{ fontSize: "11px", color: COLORS.blue, textDecoration: "none", flexShrink: 0, padding: "4px 8px", borderRadius: "6px", border: `1px solid ${COLORS.blue}40`, backgroundColor: `${COLORS.blue}10` }}
                    onClick={e => e.stopPropagation()}>
                    View →
                  </a>
                </div>
              );
            })()}
          </div>
        )}
      </div>
    </>
  );
}

function ShapBar({ feature, value }) {
  const isPositive = value > 0;
  const width = Math.min(Math.abs(value) * 300, 100);
  return (
    <div className="flex items-center gap-3 py-1.5">
      <div className="w-52 text-xs truncate flex-shrink-0" style={{ color: COLORS.muted }}>
        {feature.replace(/_/g, " ")}
      </div>
      <div className="flex-1 flex items-center gap-2">
        <div className="flex-1 h-2 rounded-full overflow-hidden" style={{ backgroundColor: COLORS.border }}>
          <div className="h-full rounded-full transition-all duration-700"
            style={{
              width: `${width}%`,
              backgroundColor: isPositive ? COLORS.critical : COLORS.low,
              marginLeft: isPositive ? "0" : "auto"
            }} />
        </div>
        <div className="text-xs font-mono w-14 text-right flex-shrink-0"
          style={{ color: isPositive ? COLORS.critical : COLORS.low }}>
          {isPositive ? "+" : ""}{(value * 100).toFixed(1)}%
        </div>
      </div>
    </div>
  );
}
function ApiKeysPage({ token, userPlan }) {
  const [keys,     setKeys]     = useState([]);
  const [loading,  setLoading]  = useState(true);
  const [newKey,   setNewKey]   = useState(null);
  const [keyName,  setKeyName]  = useState("");
  const [creating, setCreating] = useState(false);
  const [error,    setError]    = useState("");

  // Fetch all API keys on load
  useEffect(() => {
    fetchKeys();
  }, []);

  const fetchKeys = async () => {
    setLoading(true);
    try {
      const res = await axios.get("http://localhost:5001/api/keys", {
        headers: { Authorization: `Bearer ${token}` }
      });
      setKeys(res.data.keys);
    } catch (e) {
      setError(e.response?.data?.error || "Failed to create API key.");
    } finally {
      setLoading(false);
    }
  };

  const createKey = async () => {
    if (!keyName.trim()) {
      setError("Please enter a name for your API key.");
      return;
    }
    setCreating(true);
    setError("");
    try {
      const res = await axios.post(
        "http://localhost:5001/api/keys",
        { name: keyName },
        { headers: { Authorization: `Bearer ${token}` } }
      );
      setNewKey(res.data.key);
      setKeyName("");
      fetchKeys();
    } catch (e) {
      setError(e.response?.data?.error || "Failed to create API key.");
    } finally {
      setCreating(false);
    }
  };

  const revokeKey = async (keyId, keyName) => {
    if (!window.confirm(`Revoke API key "${keyName}"? This cannot be undone.`)) return;
    try {
      await axios.delete(`http://localhost:5001/api/keys/${keyId}`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      fetchKeys();
    } catch (e) {
      setError("Failed to revoke API key.");
    }
  };

  // Non-enterprise users see upgrade prompt
  if (userPlan !== "enterprise") {
    return (
      <div className="rounded-2xl border p-8 text-center max-w-lg mx-auto"
        style={{ backgroundColor: COLORS.card, borderColor: COLORS.border }}>
        <Lock size={48} style={{ color: COLORS.purple }} className="mx-auto mb-4" />
        <h3 className="text-xl font-black mb-2" style={{ color: COLORS.text }}>
          API Access — Enterprise Only
        </h3>
        <p className="text-sm mb-6" style={{ color: COLORS.muted }}>
          API keys allow you to integrate AIPET into your own systems,
          CI/CD pipelines, and security tools. Available on the Enterprise plan.
        </p>
        <button
          onClick={() => window.location.href = "/pricing"}
          className="px-6 py-3 rounded-xl font-bold text-sm"
          style={{ backgroundColor: COLORS.purple, color: "white" }}>
          Upgrade to Enterprise — £499/month
        </button>
      </div>
    );
  }

  return (
    <div className="space-y-6 max-w-3xl">

      {/* Header */}
      <div className="rounded-2xl border p-6"
        style={{ backgroundColor: COLORS.card, borderColor: COLORS.border }}>
        <h3 className="font-black text-lg mb-1" style={{ color: COLORS.text }}>
          API Keys
        </h3>
        <p className="text-sm" style={{ color: COLORS.muted }}>
          Use API keys to authenticate programmatic access to AIPET.
          Keep your keys secret — treat them like passwords.
        </p>
      </div>

      {/* New key revealed — show once */}
      {newKey && (
        <div className="rounded-2xl border p-6"
          style={{
            backgroundColor: COLORS.low + "10",
            borderColor: COLORS.low + "40"
          }}>
          <div className="flex items-center gap-2 mb-3">
            <CheckCircle size={18} style={{ color: COLORS.low }} />
            <span className="font-bold text-sm" style={{ color: COLORS.low }}>
              API key created — copy it now, it will not be shown again
            </span>
          </div>
          <div className="p-3 rounded-xl font-mono text-xs break-all"
            style={{ backgroundColor: COLORS.darker, color: COLORS.text }}>
            {newKey}
          </div>
          <button
            onClick={() => { navigator.clipboard.writeText(newKey); }}
            className="mt-3 px-4 py-2 rounded-xl text-xs font-bold"
            style={{ backgroundColor: COLORS.low, color: "white" }}>
            Copy to clipboard
          </button>
          <button
            onClick={() => setNewKey(null)}
            className="mt-3 ml-2 px-4 py-2 rounded-xl text-xs font-bold"
            style={{ backgroundColor: COLORS.border, color: COLORS.muted }}>
            I have copied it
          </button>
        </div>
      )}

      {/* Error message */}
      {error && (
        <div className="p-3 rounded-xl text-sm"
          style={{
            backgroundColor: COLORS.critical + "15",
            borderColor: COLORS.critical + "40",
            color: COLORS.critical,
            border: "1px solid"
          }}>
          {error}
        </div>
      )}

      {/* Create new key */}
      <div className="rounded-2xl border p-6"
        style={{ backgroundColor: COLORS.card, borderColor: COLORS.border }}>
        <h4 className="font-bold mb-4" style={{ color: COLORS.text }}>
          Generate new API key
        </h4>
        <div className="flex gap-3">
          <input
            type="text"
            value={keyName}
            onChange={e => setKeyName(e.target.value)}
            placeholder="e.g. Production CI/CD, SIEM Integration"
            className="flex-1 px-4 py-3 rounded-xl text-sm outline-none"
            style={{
              backgroundColor: COLORS.darker,
              color: COLORS.text,
              border: `1px solid ${COLORS.border}`
            }}
          />
          <button
            onClick={createKey}
            disabled={creating}
            className="px-6 py-3 rounded-xl font-bold text-sm transition-all"
            style={{
              backgroundColor: creating ? COLORS.border : COLORS.blue,
              color: creating ? COLORS.muted : "white"
            }}>
            {creating ? "Creating..." : "Generate"}
          </button>
        </div>
      </div>

      {/* List of keys */}
      <div className="rounded-2xl border overflow-hidden"
        style={{ backgroundColor: COLORS.card, borderColor: COLORS.border }}>
        <div className="p-4 border-b flex items-center justify-between"
          style={{ borderColor: COLORS.border }}>
          <span className="font-bold text-sm" style={{ color: COLORS.text }}>
            Active API keys ({keys.length}/10)
          </span>
        </div>

        {loading ? (
          <div className="p-8 text-center">
            <p className="text-sm" style={{ color: COLORS.muted }}>Loading...</p>
          </div>
        ) : keys.length === 0 ? (
          <div className="p-8 text-center">
            <p className="text-sm" style={{ color: COLORS.muted }}>
              No API keys yet. Generate your first key above.
            </p>
          </div>
        ) : (
          <div className="divide-y" style={{ borderColor: COLORS.border }}>
            {keys.map(key => (
              <div key={key.id}
                className="p-4 flex items-center justify-between">
                <div>
                  <div className="font-semibold text-sm mb-1"
                    style={{ color: COLORS.text }}>
                    {key.name}
                  </div>
                  <div className="text-xs font-mono mb-1"
                    style={{ color: COLORS.muted }}>
                    {key.key_preview}
                  </div>
                  <div className="text-xs" style={{ color: COLORS.muted }}>
                    Created {key.created_at?.split("T")[0]} · Last used: {key.last_used === "Never" ? "Never" : key.last_used?.split("T")[0]}
                  </div>
                </div>
                <button
                  onClick={() => revokeKey(key.id, key.name)}
                  className="px-4 py-2 rounded-xl text-xs font-bold transition-all border"
                  style={{
                    backgroundColor: "transparent",
                    borderColor: COLORS.critical + "40",
                    color: COLORS.critical
                  }}>
                  Revoke
                </button>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Usage example */}
      <div className="rounded-2xl border p-6"
        style={{ backgroundColor: COLORS.card, borderColor: COLORS.border }}>
        <h4 className="font-bold mb-3" style={{ color: COLORS.text }}>
          How to use your API key
        </h4>
        <p className="text-xs mb-3" style={{ color: COLORS.muted }}>
          Include your API key in the request header:
        </p>
        <div className="p-3 rounded-xl font-mono text-xs"
          style={{ backgroundColor: COLORS.darker, color: COLORS.low }}>
          {`curl https://aipet.io/api/scan/start \\`}<br/>
          {`  -H "X-API-Key: aipet_ent_your_key_here" \\`}<br/>
          {`  -d '{"target": "192.168.1.0/24", "mode": "live"}'`}
        </div>
      </div>

    </div>
  );
}
